section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/qa-session-based-test-management.json",
  "type": "object",
  "title": "QA Session-Based Test Management",
  "required": [
    "session_id",
    "charter",
    "tester",
    "duration_minutes",
    "split",
    "findings",
    "debrief_notes",
    "build_under_test"
  ],
  "additionalProperties": false,
  "properties": {
    "session_id": {
      "type": "string",
      "minLength": 1,
      "description": "Session identifier."
    },
    "charter": {
      "type": "string",
      "minLength": 1,
      "description": "One-paragraph mission."
    },
    "tester": {
      "type": "string",
      "minLength": 1,
      "description": "Tester handle."
    },
    "duration_minutes": {
      "type": "integer",
      "description": "60-120."
    },
    "split": {
      "type": "object",
      "description": "{T: pct, B: pct, S: pct} summing to 100."
    },
    "findings": {
      "type": "array",
      "items": {
        "type": "object"
      },
      "description": "Findings {id, type \u2208 [bug, issue, task], severity, summary}."
    },
    "debrief_notes": {
      "type": "string",
      "minLength": 1,
      "description": "Debrief summary."
    },
    "build_under_test": {
      "type": "string",
      "minLength": 1,
      "description": "Build/RC identifier."
    }
  }
}

example.code:
{
  "session_id": "sbtm-2026-05-23-001",
  "charter": "Explore the bulk role-edit flow as an admin user; mission: surface inconsistencies between filter and bulk action.",
  "tester": "alice",
  "duration_minutes": 90,
  "split": {
    "T": 60,
    "B": 25,
    "S": 15
  },
  "findings": [
    {
      "id": "f1",
      "type": "bug",
      "severity": "S2",
      "summary": "Bulk role-edit ignores admin filter when applied via the toolbar."
    }
  ],
  "debrief_notes": "Filter inconsistencies look architectural; recommend a deeper session focused on filter state across UI components.",
  "build_under_test": "v2.4.0-rc1"
}
